  1→import { test, expect, Page } from "@playwright/test";
  2→
  3→// Generate unique email per test run to avoid collisions with existing data
  4→const testEmail = `e2e-${Date.now()}@example.com`;
  5→const testPassword = "securepassword123";
  6→
  7→// Helper: fill the registration form.
  8→// The password-toggle.js progressive enhancement removes the confirm password
  9→// field and replaces it with a hidden input that mirrors the password value.
 10→// We wait for the page to settle, then only fill the confirm field if it's
 11→// still visible (i.e., JS hasn't run or hasn't removed it yet).
 12→async function fillRegistrationForm(
 13→  page: Page,
 14→  email: string,
 15→  password: string
 16→) {
 17→  // Wait for the page to fully load (including deferred scripts)
 18→  await page.waitForLoadState("networkidle");
 19→
 20→  await page.getByLabel("Email").fill(email);
 21→  await page.getByLabel("Password", { exact: true }).fill(password);
 22→
 23→  // After JS runs, the confirm field may be removed.
 24→  // Check if it's still in the DOM and visible.
 25→  const confirmCount = await page
 26→    .getByLabel("Confirm password")
 27→    .count();
 28→  if (confirmCount > 0) {
 29→    const isVisible = await page
 30→      .getByLabel("Confirm password")
 31→      .isVisible();
 32→    if (isVisible) {
 33→      await page.getByLabel("Confirm password").fill(password);
 34→    }
 35→  }
 36→
 37→  await page.getByRole("button", { name: "Create account" }).click();
 38→}
 39→
 40→test.describe("Core user journey", () => {
 41→  test("visitor sees register and sign in links on index page", async ({
 42→    page,
 43→  }) => {
 44→    await page.goto("/");
 45→
 46→    await expect(page).toHaveTitle("Todo List");
 47→    await expect(
 48→      page.getByRole("heading", { name: "Welcome" })
 49→    ).toBeVisible();
 50→    await expect(
 51→      page.getByRole("link", { name: "Create account" }).first()
 52→    ).toBeVisible();
 53→    await expect(
 54→      page.getByRole("link", { name: "Sign in" }).first()
 55→    ).toBeVisible();
 56→  });
 57→
 58→  test("full user journey: register, add, complete, delete, logout", async ({
 59→    page,
 60→  }) => {
 61→    // 1. Visit index and click Create account (the visible hero CTA)
 62→    await page.goto("/");
 63→    await page
 64→      .locator(".landing-hero")
 65→      .getByRole("link", { name: "Create account" })
 66→      .click();
 67→    await expect(page).toHaveURL(/\/register/);
 68→
 69→    // 2. Fill registration form and submit
 70→    await fillRegistrationForm(page, testEmail, testPassword);
 71→
 72→    // Should redirect to login after registration
 73→    await expect(page).toHaveURL(/\/login/);
 74→
 75→    // 3. Log in
 76→    await page.getByLabel("Email").fill(testEmail);
 77→    await page.getByLabel("Password").fill(testPassword);
 78→    await page.getByRole("button", { name: "Sign in" }).click();
 79→
 80→    // Should redirect to todos
 81→    await expect(page).toHaveURL(/\/todos/);
 82→    await expect(
 83→      page.getByRole("heading", { name: "My Todos" })
 84→    ).toBeVisible();
 85→
 86→    // 4. Add a todo
 87→    await page.getByLabel("New todo").fill("Buy groceries");
 88→    await page.getByRole("button", { name: "Add todo" }).click();
 89→
 90→    // The todo should appear in the list
 91→    await expect(page.getByText("Buy groceries")).toBeVisible();
 92→
 93→    // 5. Complete the todo (click the toggle button)
 94→    await page
 95→      .getByRole("button", { name: /Mark .+Buy groceries.+ as complete/ })
 96→      .click();
 97→
 98→    // After toggling, the page should still show the todo
 99→    // (either via HTMX swap or page reload)
100→    await expect(page.getByText("Buy groceries")).toBeVisible();
101→
102→    // 6. Delete the todo
103→    // The delete uses a <details>/<summary> confirmation pattern
104→    await page
105→      .locator('[aria-label*="Delete"][aria-label*="Buy groceries"]')
106→      .click();
107→    // Click the confirm delete button
108→    await page.getByRole("button", { name: "Yes" }).click();
109→
110→    // The todo should be removed
111→    await expect(page.getByText("Buy groceries")).not.toBeVisible();
112→
113→    // 7. Logout
114→    await page.getByRole("button", { name: "Sign out" }).click();
115→
116→    // Should redirect to login, then we go to index
117→    await page.goto("/");
118→    await expect(
119→      page.getByRole("link", { name: "Create account" }).first()
120→    ).toBeVisible();
121→    await expect(
122→      page.getByRole("link", { name: "Sign in" }).first()
123→    ).toBeVisible();
124→  });
125→
126→  test("welcome page nav links are visually hidden", async ({ page }) => {
127→    await page.goto("/");
128→
129→    // The nav links exist in the DOM for screen readers
130→    const nav = page.locator("nav");
131→    const navCreateLink = nav.getByRole("link", { name: "Create account" });
132→    const navSignInLink = nav.getByRole("link", { name: "Sign in" });
133→
134→    await expect(navCreateLink).toBeAttached();
135→    await expect(navSignInLink).toBeAttached();
