141→    expect(createBox!.height).toBeLessThanOrEqual(1);
142→
143→    const signInBox = await navSignInLink.boundingBox();
144→    expect(signInBox).not.toBeNull();
145→    expect(signInBox!.width).toBeLessThanOrEqual(1);
146→    expect(signInBox!.height).toBeLessThanOrEqual(1);
147→  });
148→
149→  test("todo toggle checkbox characters are visible", async ({ page }) => {
150→    const email = `e2e-toggle-${Date.now()}@example.com`;
151→
152→    // Register and login
153→    await page.goto("/register");
154→    await fillRegistrationForm(page, email, testPassword);
155→    await page.goto("/login");
156→    await page.getByLabel("Email").fill(email);
157→    await page.getByLabel("Password").fill(testPassword);
158→    await page.getByRole("button", { name: "Sign in" }).click();
159→    await expect(page).toHaveURL(/\/todos/);
160→
161→    // Add a todo so we have a toggle button
162→    await page.getByLabel("New todo").fill("Test item");
163→    await page.getByRole("button", { name: "Add todo" }).click();
164→    await expect(page.getByText("Test item")).toBeVisible();
165→
166→    // The toggle button should NOT have white text color
167→    const toggleButton = page.getByRole("button", {
168→      name: /Mark .+Test item.+ as complete/,
169→    });
170→    await expect(toggleButton).toBeVisible();
171→
172→    const color = await toggleButton.evaluate(
173→      (el) => getComputedStyle(el).color
174→    );
175→    // White is rgb(255, 255, 255) -- toggle should NOT be white
176→    expect(color).not.toBe("rgb(255, 255, 255)");
177→  });
178→
179→  test("authenticated user is redirected from index to todos", async ({
180→    page,
181→  }) => {
182→    const email = `e2e-redirect-${Date.now()}@example.com`;
183→
184→    // Register
185→    await page.goto("/register");
186→    await fillRegistrationForm(page, email, testPassword);
187→
188→    // Login
189→    await page.goto("/login");
190→    await page.getByLabel("Email").fill(email);
191→    await page.getByLabel("Password").fill(testPassword);
192→    await page.getByRole("button", { name: "Sign in" }).click();
193→    await expect(page).toHaveURL(/\/todos/);
194→
195→    // Now visit index -- should redirect to /todos
196→    await page.goto("/");
197→    await expect(page).toHaveURL(/\/todos/);
198→  });
199→});
